/**
 * Model User
 * User account with role-based access control.
 * Links to Profile (personal info) and optional Player record.
 */
export type User = $Result.DefaultSelection<Prisma.$UserPayload>
/**
 * Model Session
 * 
 */
export type Session = $Result.DefaultSelection<Prisma.$SessionPayload>
/**
 * Model Profile
 * User profile with personal information.
 * Separated from User to keep auth data clean.
 */
export type Profile = $Result.DefaultSelection<Prisma.$ProfilePayload>
/**
 * Model Team
 * Football team/squad (Senior, U21, Women, etc.)
 */
export type Team = $Result.DefaultSelection<Prisma.$TeamPayload>
/**
 * Model Player
 * Player profile linked to a user and a team.
 * Contains position, jersey number, and current status.
 */
export type Player = $Result.DefaultSelection<Prisma.$PlayerPayload>
/**
 * Model Match
 * A football match with home/away teams and scores.
 */
export type Match = $Result.DefaultSelection<Prisma.$MatchPayload>
/**
 * Model Statistics
 * Individual player statistics for a specific match.
 */
export type Statistics = $Result.DefaultSelection<Prisma.$StatisticsPayload>
/**
 * Model MedicalRecord
 * Medical record tracking injuries, diagnoses, and recovery timelines.
 */
export type MedicalRecord = $Result.DefaultSelection<Prisma.$MedicalRecordPayload>
/**
 * Model Finance
 * 
 */
export type Finance = $Result.DefaultSelection<Prisma.$FinancePayload>
/**
 * Model Contract
 * Player contract with financial details and duration.
 */
export type Contract = $Result.DefaultSelection<Prisma.$ContractPayload>
/**
 * Model Training
 * Training session record.
 */
export type Training = $Result.DefaultSelection<Prisma.$TrainingPayload>
/**
 * Model TrainingAttendance
 * Tracks which players attended which training sessions.
 */
export type TrainingAttendance = $Result.DefaultSelection<Prisma.$TrainingAttendancePayload>
/**
 * Model Article
 * Shop article (jersey, merchandise, etc.)
 */
export type Article = $Result.DefaultSelection<Prisma.$ArticlePayload>
/**
 * Model Order
 * Customer order from the online shop.
 */
export type Order = $Result.DefaultSelection<Prisma.$OrderPayload>
/**
 * Model OrderItem
 * Individual item in an order.
 */
export type OrderItem = $Result.DefaultSelection<Prisma.$OrderItemPayload>
/**
 * Model Ticket
 * Match ticket for fans.
 */
export type Ticket = $Result.DefaultSelection<Prisma.$TicketPayload>
/**
 * Model News
 * News article for the fan zone.
 */
export type News = $Result.DefaultSelection<Prisma.$NewsPayload>
/**
 * Model LoyaltyTransaction
 * Tracks loyalty points transactions (earn/spend).
 */
export type LoyaltyTransaction = $Result.DefaultSelection<Prisma.$LoyaltyTransactionPayload>
/**
 * Model ClubSettings
 * 
 */
export type ClubSettings = $Result.DefaultSelection<Prisma.$ClubSettingsPayload>

